---
import { getMediaFiles } from '../../lib/googleDrive';
const { activityId } = Astro.props;

// 1. Ambil data awal di server untuk SEO & First Contentful Paint
const data = await getMediaFiles(activityId, null, 4);
const initialFiles = data.files || [];
const initialToken = data.nextPageToken || null;
---

<file-gallery data-activity={activityId} data-token={initialToken}>
  <div id="grid" class="grid grid-cols-2 md:grid-cols-4 gap-4 min-h-fit">
    {initialFiles.map((file) => (
      <div class="photo-card group relative aspect-square bg-slate-100 rounded-2xl overflow-hidden border border-slate-200 cursor-pointer" 
           data-id={file.id} data-url={file.webContentLink}>
        <img src={`https://drive.google.com/thumbnail?id=${file.id}&sz=w1000`} 
          referrerpolicy="no-referrer"
             alt={file.name} class="w-full h-full object-cover transition-transform duration-500 group-hover:scale-110" loading="lazy" />
        <div class="absolute inset-0 bg-gradient-to-t from-black/80 flex flex-col justify-end p-3 opacity-0 group-hover:opacity-100 transition-opacity">
          <p class="text-[10px] text-white font-bold truncate">{file.name}</p>
        </div>
      </div>
    ))}
  </div>

  <div id="sensor" class="w-full h-20 flex justify-center items-center mt-4">
    <div class="animate-spin rounded-full h-6 w-6 border-b-2 border-blue-600"></div>
  </div>

  <div id="modal" class="fixed inset-0 z-50 flex items-center justify-center bg-black/95 hidden opacity-0 transition-all duration-300 backdrop-blur-sm">
    <button id="close-modal" class="absolute top-4 right-4 text-white p-2">✕</button>
    <div class="relative max-w-[95vw] max-h-[90vh] flex flex-col items-center">
      <img id="modal-img" class="max-h-[85vh] w-auto object-contain rounded-lg opacity-0 transition-opacity duration-500" />
      <a id="download-btn" href="" target="_blank" class="mt-5 px-6 py-2 bg-white text-black text-xs font-bold rounded-full">Download</a>
    </div>
  </div>
</file-gallery>

<script>
  class FileGallery extends HTMLElement {
    constructor() {
      super();
      this.isFetching = false;
      this.token = this.dataset.token;
      this.activityId = this.dataset.activity;
      this.observer = null;
    }

    connectedCallback() {
      this.grid = this.querySelector('#grid');
      this.sensor = this.querySelector('#sensor');
      this.modal = this.querySelector('#modal');
      this.modalImg = this.querySelector('#modal-img');

      this.setupEventListeners();
      this.setupObserver();
    }

    disconnectedCallback() {
      if (this.observer) {
        this.observer.disconnect();
      }
    }

    setupEventListeners() {
      this.grid.addEventListener('click', (e) => {
        const card = e.target.closest('.photo-card');
        if (card) this.openModal(card.dataset.id, card.dataset.url);
      });

      this.querySelector('#close-modal').onclick = () => this.closeModal();
      this.modal.onclick = (e) => { if(e.target === this.modal) this.closeModal(); };
    }

    setupObserver() {
      if (!this.token || this.token === "null") {
        this.sensor?.classList.add('hidden');
        return;
      }

      this.observer = new IntersectionObserver((entries) => {
        if (entries[0].isIntersecting) {
          this.loadMore();
        }
      }, { rootMargin: '400px' });

      this.observer.observe(this.sensor);
    }

    async loadMore() {
      if (this.isFetching || !this.token || this.token === "null") return;
      this.isFetching = true;

      try {
        const res = await fetch(`/api/drive-files?folderId=${this.activityId}&pageToken=${this.token}&limit=8`);
        const data = await res.json();

        if (data.files && data.files.length > 0) {
          this.renderNewPhotos(data.files);
          this.token = data.nextPageToken;
        } else {
          this.token = null;
        }

        if (!this.token || this.token === "null") {
          this.sensor.classList.add('hidden');
          this.observer.disconnect();
        }
      } catch (err) {
        console.error("Gagal memuat foto:", err);
      } finally {
        this.isFetching = false;
      }
    }

    renderNewPhotos(files) {
      files.forEach(file => {
        const html = `
          <div class="photo-card group relative aspect-square bg-slate-100 rounded-2xl overflow-hidden border border-slate-200 cursor-pointer" 
               data-id="${file.id}" data-url="${file.webContentLink}">
            <img src="https://drive.google.com/thumbnail?id=${file.id}&sz=w1000" class="w-full h-full object-cover transition-transform duration-500 group-hover:scale-110" loading="lazy" />
            <div class="absolute inset-0 bg-gradient-to-t from-black/80 flex flex-col justify-end p-3 opacity-0 group-hover:opacity-100 transition-opacity">
               <p class="text-[10px] text-white font-bold truncate">${file.name}</p>
            </div>
          </div>`;
        this.grid.insertAdjacentHTML('beforeend', html);
      });
    }

    openModal(id, downloadUrl) {
      this.modalImg.src = `https://drive.google.com/thumbnail?id=${id}&sz=w1600`;
      this.querySelector('#download-btn').href = downloadUrl;
      this.modal.classList.remove('hidden');
      setTimeout(() => {
        this.modal.classList.add('opacity-100');
        this.modalImg.classList.remove('opacity-0');
      }, 10);
    }

    closeModal() {
      this.modal.classList.remove('opacity-100');
      setTimeout(() => {
        this.modal.classList.add('hidden');
        this.modalImg.src = '';
      }, 300);
    }
  }

  if (!customElements.get('file-gallery')) {
    customElements.define('file-gallery', FileGallery);
  }
</script>

