// Auth Locals
const user = Astro.locals.user;
const userName = Astro.locals.user_name;
const role = Astro.locals.role;

// Nav Config
const navLinks = [
  { name: "Beranda", href: "/" },
  { name: "Galeri", href: "/dokumentasi" },
