];
---

<header-nav>
  <nav id="main-nav" class="fixed top-3 inset-x-3 md:inset-x-6 z-[60] max-w-7xl mx-auto bg-white/80 backdrop-blur-md border border-slate-200/50 shadow-sm rounded-2xl transition-all duration-300">
    <div class="px-5 sm:px-8">
      <div class="flex justify-between items-center h-16">
        <a href="/" class="flex items-center gap-3 group">
          <img src="/literasi-brebesan.webp" alt="Logo" class="w-8 h-8 rounded-full border border-slate-100 shadow-sm" />
          <div class="flex flex-col leading-none pt-0.5">
            <span class="font-black text-[11px] uppercase tracking-[0.25em] text-slate-900">LIBES</span>
