            <a href={link.href} class="px-4 py-2 text-[11px] font-bold text-slate-600 hover:text-blue-600 rounded-xl transition-all uppercase tracking-wider">
              {link.name}
            </a>
          ))}
          <div class="h-6 w-px bg-slate-200 mx-2"></div>
          {user ? (
            <div class="flex items-center gap-2">
              <a href={role === 'admin' ? '/admin' : '/user'} class="px-4 py-2 text-[11px] font-bold text-slate-900 hover:bg-slate-50 rounded-xl transition-all uppercase tracking-wider flex items-center gap-2">
                <div class="w-5 h-5 rounded-lg bg-blue-600 flex items-center justify-center text-white text-[8px] font-black uppercase">{userName?.charAt(0)}</div>
                Profil
              </a>
              <form action="/api/auth/signout" method="POST" class="m-0">
                <button type="submit" class="px-4 py-2 text-[10px] font-bold text-rose-600 hover:bg-rose-50 rounded-xl transition-all uppercase tracking-widest cursor-pointer">Keluar</button>
              </form>
            </div>
          ) : (
            <a href="/login" class="bg-slate-900 text-white px-6 py-2.5 rounded-2xl text-[10px] font-bold hover:bg-blue-600 hover:shadow-lg hover:shadow-blue-200 transition-all uppercase tracking-widest">Masuk</a>
          )}
        </div>

        <button id="menu-btn" class="md:hidden w-10 h-10 flex items-center justify-center bg-slate-50 text-slate-900 rounded-xl border border-slate-200/50">
          <div class="flex flex-col gap-1.5 w-4">
            <span id="l1" class="w-full h-0.5 bg-current rounded-full transition-all"></span>
            <span id="l2" class="w-full h-0.5 bg-current rounded-full transition-all"></span>
          </div>
        </button>
      </div>
    </div>
  </nav>

  <div id="overlay" class="fixed inset-0 bg-slate-950/10 backdrop-blur-[1px] z-[80] hidden opacity-0 transition-opacity duration-300"></div>

  <aside id="drawer" class="fixed top-20 right-2 w-[220px] bg-white z-[90] translate-x-[110%] transition-transform duration-300 ease-in-out shadow-2xl rounded-2xl border border-slate-100 flex flex-col">
    <div class="p-6 flex flex-col h-auto text-left">
      <div class="mb-6 pt-2">
        <span class="text-[9px] font-black text-slate-400 uppercase tracking-[0.2em]">Navigasi Utama</span>
      </div>
      <nav class="flex flex-col gap-1">
        {navLinks.map((link) => (
          <a href={link.href} class="px-3 py-3 text-xs font-bold text-slate-700 hover:bg-blue-50 hover:text-blue-600 rounded-xl transition-all text-left">{link.name}</a>
        ))}
      </nav>
      <div class="mt-6 pt-6 border-t border-slate-100 flex flex-col gap-3">
        {user ? (
          <>
            <a href={role === 'admin' ? '/admin' : '/user'} class="flex items-center gap-3 px-3 py-3 bg-slate-50 rounded-xl text-xs font-bold text-slate-900">
              <div class="w-6 h-6 rounded-lg bg-blue-600 flex items-center justify-center text-white text-[10px] font-black uppercase">{userName?.charAt(0)}</div>
              Dashboard Profil
            </a>
            <form action="/api/auth/signout" method="POST" class="w-full m-0">
              <button type="submit" class="w-full text-center py-3 text-[10px] font-black text-rose-600 uppercase tracking-widest cursor-pointer">Keluar dari Akun</button>
            </form>
          </>
        ) : (
          <a href="/login" class="flex items-center justify-center bg-blue-600 text-white py-4 rounded-2xl text-[10px] font-bold uppercase tracking-widest shadow-lg shadow-blue-200">Masuk / Gabung</a>
        )}
      </div>
    </div>
  </aside>
</header-nav>

<script>
  class HeaderNav extends HTMLElement {
    constructor() {
      super();
      this.isOpen = false;
    }

    connectedCallback() {
      this.btn = this.querySelector('#menu-btn');
      this.drawer = this.querySelector('#drawer');
      this.overlay = this.querySelector('#overlay');
      this.l1 = this.querySelector('#l1');
      this.l2 = this.querySelector('#l2');

      this.btn?.addEventListener('click', () => this.toggleMenu());
      this.overlay?.addEventListener('click', () => this.toggleMenu());

      // Menutup drawer jika link diklik (penting untuk SPA)
      this.querySelectorAll('aside a').forEach(link => {
        link.addEventListener('click', () => this.toggleMenu(false));
      });
    }

    toggleMenu(force) {
      this.isOpen = force !== undefined ? force : !this.isOpen;

      if (this.isOpen) {
        this.overlay?.classList.remove('hidden');
        setTimeout(() => this.overlay?.classList.add('opacity-100'), 10);
        this.drawer?.classList.remove('translate-x-[110%]');
        // Animasi icon hamburger
        this.l1?.classList.add('rotate-45', 'translate-y-[3px]');
        this.l2?.classList.add('-rotate-45', '-translate-y-[3px]');
      } else {
        this.overlay?.classList.remove('opacity-100');
        setTimeout(() => this.overlay?.classList.add('hidden'), 300);
        this.drawer?.classList.add('translate-x-[110%]');
        // Reset icon hamburger
        this.l1?.classList.remove('rotate-45', 'translate-y-[3px]');
        this.l2?.classList.remove('-rotate-45', '-translate-y-[3px]');
      }
    }
  }

  customElements.define('header-nav', HeaderNav);
</script>

