<script>
  // Script Client-side untuk menangani Modal
  document.addEventListener('astro:page-load', () => {
    const modal = document.getElementById('modal-rejection') as HTMLDialogElement;
    const btnClose = document.getElementById('btn-close-rejection');
    const inputId = document.getElementById('rejection-article-id') as HTMLInputElement;
    const labelTitle = document.getElementById('rejection-target-title');
    const openButtons = document.querySelectorAll('.btn-open-rejection');

    openButtons.forEach(button => {
      button.addEventListener('click', () => {
        const id = (button as HTMLElement).getAttribute('data-article-id');
        const title = (button as HTMLElement).getAttribute('data-article-title');

        if (id && modal) {
          inputId.value = id;
          if (labelTitle) labelTitle.textContent = title || "Artikel Tanpa Judul";
          modal.showModal();
        }
      });
    });

    btnClose?.addEventListener('click', () => {
      modal?.close();
    });

    // Tutup modal jika klik di luar area konten (backdrop)
    modal?.addEventListener('click', (e) => {
      if (e.target === modal) {
        modal.close();
      }
    });
  });
</script>

