    </div>

  </div>
</DashboardLayout>

args.content:
---
import Layout from "../../layouts/Layout.astro";
import Header from "../../components/Header.astro";
import Footer from "../../components/Footer.astro";
import { supabase } from "../../lib/supabase";
import { ArticleService } from "../../services/articleService";
import { CommentSection } from "../../components/features/ruang-suara/CommentSection";
import Badge from "../../components/ui/Badge.astro";
import { formatDate } from "../../utils/date";

const { id } = Astro.params;
const articleService = new ArticleService(supabase);

// Ambil detail artikel berdasarkan ID
const { data: article, error } = await articleService.getArticleById(id!);

if (error || !article) {
  return Astro.redirect('/ruang-suara');
}

// Cek User untuk Komentar
const user = Astro.locals.user;
const currentUserId = user?.id;
const currentUserName = Astro.locals.user_name;

// Determine badge variant
const getBadgeVariant = (category: string) => {
  if (category === 'Tips') return 'success';
  if (category === 'Opini') return 'warning';
  return 'primary';
};
---

<Layout title={`${article.title} - Ruang Suara`} description={article.excerpt || article.content.substring(0, 160)}>
  <Header transition:persist />

  <main class="pt-32 pb-20 px-4 min-h-screen bg-white">
    <article class="container mx-auto max-w-3xl">

      <!-- Breadcrumb -->
      <nav class="flex items-center gap-2 text-slate-400 text-[10px] font-bold uppercase tracking-widest mb-10">
        <a href="/" class="hover:text-blue-600 transition-colors">Beranda</a>
        <span class="text-slate-200">/</span>
        <a href="/ruang-suara" class="hover:text-blue-600 transition-colors">Ruang Suara</a>
        <span class="text-slate-200">/</span>
        <span class="text-slate-400 truncate max-w-[150px]">{article.title}</span>
      </nav>

      <!-- Header Artikel -->
      <header class="mb-12">
        <div class="flex items-center gap-4 mb-8">
          <Badge variant={getBadgeVariant(article.category || 'Zine')}>
            {article.category || 'Zine'}
          </Badge>
          <span class="text-slate-300 text-xs">•</span>
          <time class="text-slate-500 text-xs font-bold uppercase tracking-tighter">
            {formatDate(article.created_at)}
          </time>
          <span class="text-slate-300 text-xs">•</span>
          <span class="text-slate-500 text-xs font-bold uppercase tracking-tighter flex items-center gap-1">
            {article.reading_time || 3} MIN READ
          </span>
        </div>

        <h1 class="text-4xl md:text-6xl font-extrabold text-slate-900 leading-[1.1] tracking-tight mb-8">
          {article.title}
        </h1>

        <div class="flex items-center gap-4 mb-12 p-4 bg-slate-50 rounded-2xl border border-slate-100">
          <div class="w-12 h-12 rounded-full bg-slate-900 flex items-center justify-center text-white font-bold text-lg border-2 border-white shadow-md">
            {article.profiles?.full_name?.charAt(0) || 'U'}
          </div>
          <div>
            <p class="text-sm font-bold text-slate-900">{article.profiles?.full_name || 'Penulis Anonim'}</p>
            <p class="text-[11px] text-slate-500 font-medium uppercase tracking-widest">Penulis Kolektif</p>
          </div>
          <button class="ml-auto px-6 py-2 bg-white border border-slate-200 rounded-xl text-[10px] font-black text-blue-600 uppercase tracking-widest hover:bg-blue-50 transition-colors">Ikuti</button>
        </div>

        {article.image_url && (
          <div class="relative aspect-video mb-16 rounded-[2.5rem] overflow-hidden shadow-2xl shadow-blue-900/10 border border-slate-100">
            <img 
              src={article.image_url} 
              alt={article.title} 
              class="w-full h-full object-cover"
            />
          </div>
        )}
      </header>

      <!-- Konten Utama -->
      <div class="prose prose-slate prose-lg max-w-none text-slate-700 leading-[1.8] font-serif mb-16">
        {article.content.split('\n').map((paragraph: string) => (
          paragraph ? <p class="mb-8">{paragraph}</p> : <div class="h-4"></div>
        ))}
      </div>

      <!-- Bar Interaksi (Quora Style) -->
      <div class="sticky bottom-6 z-30 flex items-center justify-between p-2 bg-white/80 backdrop-blur-md border border-slate-200 rounded-[2rem] shadow-2xl max-w-sm mx-auto animate-in slide-in-from-bottom-8 duration-500">
        <div class="flex items-center gap-1 bg-slate-100 rounded-full p-1">
          <button class="flex items-center gap-2 px-5 py-2.5 text-slate-700 hover:bg-blue-600 hover:text-white rounded-full transition-all group/up">
            <svg xmlns="http://www.w3.org/2000/svg" class="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" stroke-width="3">
              <path stroke-linecap="round" stroke-linejoin="round" d="M5 15l7-7 7 7" />
            </svg>
            <span class="text-[10px] font-black uppercase tracking-widest">Dukung</span>
          </button>
          <div class="w-px h-4 bg-slate-300 mx-1"></div>
          <button class="px-3 py-2.5 text-slate-400 hover:text-rose-600 rounded-full transition-colors">
            <svg xmlns="http://www.w3.org/2000/svg" class="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" stroke-width="3">
              <path stroke-linecap="round" stroke-linejoin="round" d="M19 9l-7 7-7-7" />
            </svg>
          </button>
        </div>

        <div class="flex items-center gap-2 px-4">
          <button class="p-3 text-slate-500 hover:bg-slate-100 rounded-full transition-colors">
            <svg xmlns="http://www.w3.org/2000/svg" class="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor" stroke-width="2">
              <path stroke-linecap="round" stroke-linejoin="round" d="M8.684 13.342C8.886 12.938 9 12.482 9 12c0-.482-.114-.938-.316-1.342m0 2.684a3 3 0 110-2.684m0 2.684l6.514 3.257m-6.514-9.924l6.514-3.257m0 0a3 3 0 110-2.684 3 3 0 010 2.684zm7.322 13.411v-2.684a3 3 0 00-3-3H6.707a2 2 0 01-1.414-.586l-1.414-1.414a2 2 0 00-.586-1.414V4.5M15 12h3" />
            </svg>
          </button>
        </div>
      </div>

      <!-- SEKSI KOMENTAR (REACT) -->
      <CommentSection 
        client:load 
        articleId={article.id.toString()} 
        currentUserId={currentUserId} 
        currentUserName={currentUserName} 
      />

      <!-- Footer Nav -->
      <div class="flex justify-center mt-20">
        <a href="/ruang-suara" class="text-blue-600 font-black text-[10px] uppercase tracking-[0.2em] flex items-center gap-2 hover:gap-4 transition-all">
          ← Kembali Jelajahi Suara
        </a>
      </div>

    </article>
  </main>

  <Footer />
</Layout>

